// Best Sellers Carousel - Slide one product at a timedocument.addEventListener('DOMContentLoaded', function () {const carousel = document.getElementById('bestSellersCarousel');const nextBtn = document.getElementById('bestSellersNext');const prevBtn = document.getElementById('bestSellersPrev');if (!carousel || !nextBtn || !prevBtn) return;const cards = carousel.querySelectorAll('.bestseller-card');const totalCards = cards.length;if (totalCards === 0) return;let currentIndex = 0;function getItemsVisible() {return window.innerWidth <= 1024 ? 1 : 4;}function updateCarousel() {const itemsVisible = getItemsVisible();const cardWidth = cards[0].offsetWidth;const style = window.getComputedStyle(carousel);const gap = parseFloat(style.gap) || 32;const slideDistance = cardWidth + gap;const maxIndex = Math.max(0, totalCards - itemsVisible);// Ensure currentIndex is within bounds if we resizedif (currentIndex > maxIndex) currentIndex = maxIndex;const translateX = -(currentIndex * slideDistance);carousel.style.transform = `translateX(${translateX}px)`;// Disable buttons at boundariesprevBtn.disabled = currentIndex === 0;nextBtn.disabled = currentIndex === maxIndex;// Visual feedback for disabled buttonsprevBtn.style.opacity = currentIndex === 0 ? '0.5' : '1';nextBtn.style.opacity = currentIndex === maxIndex ? '0.5' : '1';prevBtn.style.cursor = currentIndex === 0 ? 'not-allowed' : 'pointer';nextBtn.style.cursor = currentIndex === maxIndex ? 'not-allowed' : 'pointer';}nextBtn.addEventListener('click', function () {const itemsVisible = getItemsVisible();const maxIndex = Math.max(0, totalCards - itemsVisible);if (currentIndex < maxIndex) {currentIndex++;updateCarousel();}});prevBtn.addEventListener('click', function () {if (currentIndex > 0) {currentIndex--;updateCarousel();}});// Initialize button statessetTimeout(updateCarousel, 100);// Also update on load just in casewindow.addEventListener('load', updateCarousel);// Recalculate on window resizelet resizeTimer;window.addEventListener('resize', function () {clearTimeout(resizeTimer);resizeTimer = setTimeout(updateCarousel, 250);});});// Latest Products Carouseldocument.addEventListener('DOMContentLoaded', function () {const carousel = document.getElementById('latestProductsTrack');const nextBtn = document.getElementById('latestNext');const prevBtn = document.getElementById('latestPrev');if (!carousel || !nextBtn || !prevBtn) return;const cards = carousel.querySelectorAll('.latest-product-card');const totalCards = cards.length;if (totalCards === 0) return;let currentIndex = 0;function getItemsVisible() {return window.innerWidth <= 1024 ? 1 : 4;}function updateCarousel() {const itemsVisible = getItemsVisible();const cardWidth = cards[0].offsetWidth;// On mobile (1 item), the gap might be handled differently or included in the width if using 100%// But let's stick to the calculated slide distance based on card width + gap if applicable.// In CSS: .latest-products-track { gap: 2rem; } which is 32px.// However, offsetWidth includes padding/border.// If we use gap in CSS, we need to account for it.const style = window.getComputedStyle(carousel);const gap = parseFloat(style.gap) || 32;const slideDistance = cardWidth + gap;const maxIndex = Math.max(0, totalCards - itemsVisible);// Ensure currentIndex is within bounds if we resizedif (currentIndex > maxIndex) currentIndex = maxIndex;const translateX = -(currentIndex * slideDistance);carousel.style.transform = `translateX(${translateX}px)`;// Disable buttons at boundariesprevBtn.disabled = currentIndex === 0;nextBtn.disabled = currentIndex === maxIndex;// Visual feedback for disabled buttonsprevBtn.style.opacity = currentIndex === 0 ? '0.5' : '1';nextBtn.style.opacity = currentIndex === maxIndex ? '0.5' : '1';prevBtn.style.cursor = currentIndex === 0 ? 'not-allowed' : 'pointer';nextBtn.style.cursor = currentIndex === maxIndex ? 'not-allowed' : 'pointer';}nextBtn.addEventListener('click', function () {const itemsVisible = getItemsVisible();const maxIndex = Math.max(0, totalCards - itemsVisible);if (currentIndex < maxIndex) {currentIndex++;updateCarousel();}});prevBtn.addEventListener('click', function () {if (currentIndex > 0) {currentIndex--;updateCarousel();}});// Initialize button states// Wait for layout to be stable (sometimes offsetWidth is 0 initially if images loading)setTimeout(updateCarousel, 100);// Also update on load just in casewindow.addEventListener('load', updateCarousel);// Recalculate on window resizelet resizeTimer;window.addEventListener('resize', function () {clearTimeout(resizeTimer);resizeTimer = setTimeout(updateCarousel, 250);});});// Reviews Sliderdocument.addEventListener('DOMContentLoaded', function () {const track = document.getElementById('reviewsTrack');const nextBtn = document.getElementById('reviewNext');const prevBtn = document.getElementById('reviewPrev');if (!track || !nextBtn || !prevBtn) return;const slides = track.querySelectorAll('.review-slide');const totalSlides = slides.length;if (totalSlides === 0) return;let currentIndex = 0;function updateSlider() {const translateX = -(currentIndex * 100);track.style.transform = `translateX(${translateX}%)`;}nextBtn.addEventListener('click', function () {if (currentIndex < totalSlides - 1) {currentIndex++;} else {currentIndex = 0; // Loop back to start}updateSlider();});prevBtn.addEventListener('click', function () {if (currentIndex > 0) {currentIndex--;} else {currentIndex = totalSlides - 1; // Loop to end}updateSlider();});});// Category Filter Tabs - Dynamic Product Filteringdocument.addEventListener('DOMContentLoaded', function () {const filterButtons = document.querySelectorAll('.filter-btn');const productCards = document.querySelectorAll('.category-product-card');if (filterButtons.length === 0 || productCards.length === 0) return;// Mobile Filter Toggleconst mobileFilterToggle = document.getElementById('mobileFilterToggle');const categoryFiltersContainer = document.getElementById('categoryFilters');if (mobileFilterToggle && categoryFiltersContainer) {mobileFilterToggle.addEventListener('click', function () {categoryFiltersContainer.classList.toggle('expanded');});}filterButtons.forEach(button => {button.addEventListener('click', function (e) {e.preventDefault();const selectedCategory = this.getAttribute('data-category');// Remove active class from all buttonsfilterButtons.forEach(btn => btn.classList.remove('active'));// Selecting new categorythis.classList.add('active');// Collapse the filter list on mobile after selectionif (categoryFiltersContainer) {categoryFiltersContainer.classList.remove('expanded');}// Hide all product cardsproductCards.forEach(card => {card.style.display = 'none';});// Show only products from selected categoryconst categoryProducts = document.querySelectorAll(`[data-category="${selectedCategory}"]`);categoryProducts.forEach(card => {card.style.display = 'block';});// Smooth scroll animation for product gridconst productGrid = document.getElementById('categoryProductsGrid');if (productGrid) {productGrid.style.opacity = '0';setTimeout(() => {productGrid.style.opacity = '1';}, 100);}});});});// Smart Sticky Navbar - Sticks to top when scrolling down past headerdocument.addEventListener('DOMContentLoaded', function () {const navbar = document.querySelector('.nav-bar-full');const mobileNavbar = document.querySelector('.mobile-nav-bar');const desktopHeader = document.querySelector('.desktop-header-only');if (!navbar && !mobileNavbar) return;// Get the initial offset of navbar from toplet navbarOffset = 0;let lastScrollTop = 0;function initStickyNavbar() {// For desktopif (navbar && desktopHeader) {navbarOffset = navbar.offsetTop;}handleScroll();}function handleScroll() {const scrollTop = window.pageYOffset || document.documentElement.scrollTop;// Desktop sticky navbarif (navbar && window.innerWidth > 768) {if (scrollTop > navbarOffset) {// User has scrolled past the navbar positionif (!navbar.classList.contains('is-stuck')) {navbar.classList.add('is-stuck');// Add padding to prevent content jumpif (desktopHeader) {desktopHeader.style.paddingBottom = navbar.offsetHeight + 'px';}}} else {// User is at the topif (navbar.classList.contains('is-stuck')) {navbar.classList.remove('is-stuck');if (desktopHeader) {desktopHeader.style.paddingBottom = '0';}}}}// Mobile sticky navbarif (mobileNavbar && window.innerWidth <= 768) {const mobileHeader = document.querySelector('.mobile-header-custom');const mobileNavOffset = mobileNavbar.offsetTop;if (scrollTop > mobileNavOffset) {if (!mobileNavbar.classList.contains('is-stuck')) {mobileNavbar.classList.add('is-stuck');if (mobileHeader) {mobileHeader.style.paddingBottom = mobileNavbar.offsetHeight + 'px';}}} else {if (mobileNavbar.classList.contains('is-stuck')) {mobileNavbar.classList.remove('is-stuck');if (mobileHeader) {mobileHeader.style.paddingBottom = '0';}}}}lastScrollTop = scrollTop;}// Initialize after a short delay to ensure layout is readysetTimeout(initStickyNavbar, 100);// Update on scrollwindow.addEventListener('scroll', handleScroll, { passive: true });// Recalculate on resizelet resizeTimer;window.addEventListener('resize', function () {clearTimeout(resizeTimer);resizeTimer = setTimeout(initStickyNavbar, 250);});});